  1	import { Radio, Text, TextVariants, Tooltip } from '@patternfly/react-core';
  2	import { InfoAltIcon } from '@patternfly/react-icons';
  3	import * as React from 'react';
  4	import { useTranslation } from 'react-i18next';
  5	import { DataSource, PacketLoss, RecordType } from '../../model/flow-query';
  6	import { QueryOptionsProps } from './query-options-dropdown';
  7	
  8	export const topValues = [5, 10, 15];
  9	export const limitValues = [50, 100, 500, 1000];
 10	
 11	type RecordTypeOption = { label: string; value: RecordType };
 12	type DataSourceOption = { label: string; value: DataSource };
 13	type PacketLossOption = { label: string; value: PacketLoss };
 14	
 15	// Exported for tests
 16	export const QueryOptionsPanel: React.FC<QueryOptionsProps> = ({
 17	  recordType,
 18	  setRecordType,
 19	  dataSource,
 20	  setDataSource,
 21	  allowLoki,
 22	  allowProm,
 23	  allowFlow,
 24	  allowConnection,
 25	  allowPktDrops,
 26	  useTopK,
 27	  limit,
 28	  setLimit,
 29	  packetLoss,
 30	  setPacketLoss
 31	}) => {
 32	  const { t } = useTranslation('plugin__netobserv-plugin');
 33	
 34	  const recordTypeOptions: RecordTypeOption[] = [
 35	    {
 36	      label: t('Conversation'),
 37	      value: 'allConnections'
 38	    },
 39	    {
 40	      label: t('Flow'),
 41	      value: 'flowLog'
 42	    }
 43	  ];
 44	
 45	  const dataSourceOptions: DataSourceOption[] = [
 46	    {
 47	      label: t('Loki'),
 48	      value: 'loki'
 49	    },
 50	    {
 51	      label: t('Prometheus'),
 52	      value: 'prom'
 53	    },
 54	    {
 55	      label: t('Auto'),
 56	      value: 'auto'
 57	    }
 58	  ];
 59	
 60	  const packetLossOptions: PacketLossOption[] = [
 61	    {
 62	      label: t('Fully dropped'),
 63	      value: 'dropped'
 64	    },
 65	    {
 66	      label: t('Containing drops'),
 67	      value: 'hasDrops'
 68	    },
 69	    {
 70	      label: t('Without drops'),
 71	      value: 'sent'
 72	    },
 73	    {
 74	      label: t('All'),
 75	      value: 'all'
 76	    }
 77	  ];
 78	
 79	  const values = useTopK ? topValues : limitValues;
 80	
 81	  return (
 82	    <>
 83	      <div className="pf-v6-c-menu__group">
 84	        <Tooltip
 85	          content={t(
 86	            // eslint-disable-next-line max-len
 87	            'Log type to query. A conversation is an aggregation of flows between same peers. Only ended conversations will appear in Overview and Topology tabs.'
 88	          )}
 89	        >
 90	          <div className="pf-v6-c-menu__group-title">
 91	            <Text component={TextVariants.p}>
 92	              {t('Log type')} <InfoAltIcon />
 93	            </Text>
 94	          </div>
 95	        </Tooltip>
 96	        {recordTypeOptions.map(opt => {
 97	          const disabled =
 98	            (!allowFlow && opt.value === 'flowLog') || (!allowConnection && opt.value === 'allConnections');
 99	          return (
100	            <div key={`recordType-${opt.value}`}>
101	              <label className="display-dropdown-padding pf-v6-c-menu__menu-item">
102	                <Tooltip
103	                  trigger={disabled ? 'mouseenter focus' : ''}
104	                  content={
105	                    disabled
106	                      ? opt.value === 'allConnections'
107	                        ? t(
108	                            // eslint-disable-next-line max-len
109	                            'Only available when FlowCollector.processor.logTypes option equals "CONNECTIONS", "ENDED_CONNECTIONS" or "ALL"'
110	                          )
111	                        : t(
112	                            // eslint-disable-next-line max-len
113	                            'Only available when FlowCollector.processor.logTypes option equals "FLOWS" or "ALL"'
114	                          )
115	                      : undefined
116	                  }
117	                >
118	                  <Radio
119	                    isChecked={opt.value === recordType}
120	                    isDisabled={disabled}
121	                    name={`recordType-${opt.value}`}
122	                    onChange={() => setRecordType(opt.value)}
123	                    label={opt.label}
124	                    data-test={`recordType-${opt.value}`}
125	                    id={`recordType-${opt.value}`}
126	                    value={opt.value}
127	                  />
128	                </Tooltip>
129	              </label>
130	            </div>
131	          );
132	        })}
133	      </div>
134	      <div className="pf-v6-c-menu__group">
135	        <Tooltip
136	          content={t(
137	            // eslint-disable-next-line max-len
138	            'Which datasource to query from console plugin pod. Prometheus holds a subset of metrics compared to Loki with better performances. Select "Auto" to pick the best datasource automatically.'
139	          )}
140	        >
141	          <div className="pf-v6-c-menu__group-title">
142	            <Text component={TextVariants.p}>
143	              {t('Datasource')} <InfoAltIcon />
144	            </Text>
145	          </div>
146	        </Tooltip>
147	        {dataSourceOptions.map(opt => {
148	          const disabled = (!allowProm && opt.value === 'prom') || (!allowLoki && opt.value === 'loki');
149	          return (
150	            <div key={`dataSource-${opt.value}`}>
151	              <label className="display-dropdown-padding pf-v6-c-menu__menu-item">
152	                <Tooltip
153	                  trigger={disabled ? 'mouseenter focus' : ''}
154	                  content={
155	                    disabled
156	                      ? opt.value === 'prom'
157	                        ? t(
158	                            // eslint-disable-next-line max-len
159	                            'Only available when FlowCollector.prometheus.enable is true for Overview and Topology tabs'
160	                          )
161	                        : opt.value === 'loki'
162	                        ? t(
163	                            // eslint-disable-next-line max-len
164	                            'Only available when FlowCollector.loki.enable is true'
165	                          )
166	                        : undefined
167	                      : undefined
168	                  }
169	                >
170	                  <Radio
171	                    isChecked={opt.value === dataSource}
172	                    isDisabled={disabled}
173	                    name={`dataSource-${opt.value}`}
174	                    onChange={() => setDataSource(opt.value)}
175	                    label={opt.label}
176	                    data-test={`dataSource-${opt.value}`}
177	                    id={`dataSource-${opt.value}`}
178	                    value={opt.value}
179	                  />
180	                </Tooltip>
181	              </label>
182	            </div>
183	          );
184	        })}
185	      </div>
186	      <div className="pf-v6-c-menu__group">
187	        <Tooltip
188	          content={
189	            <div>
190	              <p className="netobserv-align-start">
191	                {t('Filter flows by their drop status. Only packets dropped by the kernel are monitored here.')}
192	              </p>
193	              <p className="netobserv-align-start"> - {t('Fully dropped shows the flows that are 100% dropped')}</p>
194	              <p className="netobserv-align-start">
195	                - {t('Containing drops shows the flows having at least one packet dropped')}
196	              </p>
197	              <p className="netobserv-align-start"> - {t('Without drops show the flows having 0% dropped')}</p>
198	              <p className="netobserv-align-start"> - {t('All shows everything')}</p>
199	            </div>
200	          }
201	        >
202	          <div className="pf-v6-c-menu__group-title">
203	            <Text component={TextVariants.p}>
204	              {t('Drops filter')} <InfoAltIcon />
205	            </Text>
206	          </div>
207	        </Tooltip>
208	        {packetLossOptions.map(opt => {
209	          const disabled = !allowPktDrops && opt.value !== 'all';
210	          return (
211	            <div key={`packet-loss-${opt.value}`}>
212	              <label className="display-dropdown-padding pf-v6-c-menu__menu-item">
213	                <Tooltip
214	                  trigger={disabled ? 'mouseenter focus' : ''}
215	                  content={
216	                    disabled
217	                      ? t(
218	                          // eslint-disable-next-line max-len
219	                          'Only available using eBPF with FlowCollector.agent.ebpf.features containing "PacketDrop"'
220	                        )
221	                      : undefined
222	                  }
223	                >
224	                  <Radio
225	                    isChecked={opt.value === packetLoss}
226	                    isDisabled={disabled}
227	                    name={`packet-loss-${opt.value}`}
228	                    onChange={() => setPacketLoss(opt.value)}
229	                    label={opt.label}
230	                    data-test={`packet-loss-${opt.value}`}
231	                    id={`packet-loss-${opt.value}`}
232	                    value={opt.value}
233	                  />
234	                </Tooltip>
235	              </label>
236	            </div>
237	          );
238	        })}
239	      </div>
240	      <div className="pf-v6-c-menu__group">
241	        <Tooltip
242	          content={
243	            (useTopK ? t('Top items for internal backend queries.') : t('Limit for internal backend queries.')) +
244	            ' ' +
245	            t(
246	              // eslint-disable-next-line max-len
247	              'Depending on the matching and filter settings, several queries can be performed under the cover, each with this parameter set, resulting in more results after aggregation.'
248	            )
249	          }
250	        >
251	          <div className="pf-v6-c-menu__group-title">
252	            <Text component={TextVariants.p}>
253	              {useTopK ? t('Top / Bottom') : t('Limit')} <InfoAltIcon />
254	            </Text>
255	          </div>
256	        </Tooltip>
257	        {values.map(l => (
258	          <div key={'limit-' + l}>
259	            <label className="display-dropdown-padding pf-v6-c-menu__menu-item">
260	              <Radio
261	                data-test={'limit-' + l}
262	                id={'limit-' + l}
263	                name={'limit-' + l}
264	                isChecked={l === limit}
265	                label={String(l)}
266	                onChange={() => setLimit(l)}
267	                value={String(l)}
268	              />
269	            </label>
270	          </div>
271	        ))}
272	      </div>
273	    </>
274	  );
275	};
276	
277	export default QueryOptionsPanel;

